import React from 'react';
import { MoneyInput, NumberInput } from '@linm-soft-org/linm-web-common-components';

export type LocaleNumberFormat = 'money' | 'quantity';

interface LocaleNumberInputProps {
  value: number;
  onChange: (value: number) => void;
  format?: LocaleNumberFormat;
  disabled?: boolean;
  error?: string;
  placeholder?: string;
  className?: string;
}

/** @deprecated Prefer MoneyInput / NumberInput from @linm-soft-org/linm-web-common-components */
export const LocaleNumberInput: React.FC<LocaleNumberInputProps> = ({
  format = 'money',
  ...props
}) =>
  format === 'money' ? (
    <MoneyInput {...props} />
  ) : (
    <NumberInput {...props} />
  );

export { MoneyInput, NumberInput } from '@linm-soft-org/linm-web-common-components';
