import { PURCHASE_INVOICE_VOUCHER_CODE } from '../../constants/purchaseInvoiceVoucherCodes';

const PREFIX_BY_VOUCHER_CODE: Record<string, string> = {
  [PURCHASE_INVOICE_VOUCHER_CODE.phieuNhapMua]: 'kt-pnm',
  [PURCHASE_INVOICE_VOUCHER_CODE.phieuNhapMuaXt]: 'kt-pnm-xt',
  [PURCHASE_INVOICE_VOUCHER_CODE.hoaDonMuaDv]: 'kt-hdmh-dv',
};

/** Shared testId prefix for PurchaseInvoiceList / PurchaseInvoiceForm variants. */
export function purchaseInvoiceTestIdPrefix(voucherCode: string): string {
  return PREFIX_BY_VOUCHER_CODE[voucherCode] ?? `kt-${voucherCode.toLowerCase()}`;
}
