/** Fallback when init-data missing — align `currency-field.md`. */
export const CURRENCY_FALLBACK_CODE = 'VND';
export const CURRENCY_FALLBACK_RATE = 1;

export function resolveVoucherCurrencyDefaults(
  defaultCurrencyCode?: string | null,
  defaultExchangeRate?: string | number | null,
): { currencyCode: string; exchangeRate: number } {
  const currencyCode = (defaultCurrencyCode?.trim() || CURRENCY_FALLBACK_CODE).toUpperCase();
  const parsed =
    defaultExchangeRate != null && defaultExchangeRate !== ''
      ? Number(defaultExchangeRate)
      : CURRENCY_FALLBACK_RATE;
  const rate = Number.isFinite(parsed) && parsed > 0 ? parsed : CURRENCY_FALLBACK_RATE;
  const exchangeRate = currencyCode === CURRENCY_FALLBACK_CODE ? CURRENCY_FALLBACK_RATE : rate;
  return { currencyCode, exchangeRate };
}

/** Map GET DTO → display values with fallback. */
export function resolveVoucherCurrencyFromDto(
  dtoCurrencyCode?: string | null,
  dtoExchangeRate?: string | number | null,
  initCurrencyCode?: string | null,
  initExchangeRate?: string | number | null,
): { currencyCode: string; exchangeRate: number } {
  if (dtoCurrencyCode?.trim()) {
    const currencyCode = dtoCurrencyCode.trim().toUpperCase();
    const parsed = dtoExchangeRate != null ? Number(dtoExchangeRate) : CURRENCY_FALLBACK_RATE;
    const rate = Number.isFinite(parsed) && parsed > 0 ? parsed : CURRENCY_FALLBACK_RATE;
    return {
      currencyCode,
      exchangeRate: currencyCode === CURRENCY_FALLBACK_CODE ? CURRENCY_FALLBACK_RATE : rate,
    };
  }
  return resolveVoucherCurrencyDefaults(initCurrencyCode, initExchangeRate);
}
